81	pub mod buffer {
82	    use alloc::{borrow::Cow, vec::Vec};
83	
84	    pub trait Buffer {
85	        /// Returns the number of bytes in the buffer.
86	        fn len(&self) -> usize;
87	
88	        /// Returns `true` if the buffer has a length of 0.
89	        fn is_empty(&self) -> bool {
90	            self.len() == 0
91	        }
92	    }
93	
94	    /// A trait for buffers that can be composed of multiple non contiguous slices.
95	    pub trait SplitBuffer: Buffer {
96	        type Slices<'a>: Iterator<Item = &'a [u8]> + ExactSizeIterator
97	        where
98	            Self: 'a;
99	
100	        /// Gets all the slices of this buffer.
101	        fn slices(&self) -> Self::Slices<'_>;
102	
103	        /// Returns all the bytes of this buffer in a contiguous slice.
104	        /// This may require allocation and copy if the original buffer
105	        /// is not contiguous.
106	        fn contiguous(&self) -> Cow<'_, [u8]> {
107	            let mut slices = self.slices();
108	            match slices.len() {
109	                0 => Cow::Borrowed(b""),
110	                1 => {
111	                    // SAFETY: unwrap here is safe because we have explicitly checked
112	                    // the iterator has 1 element.
113	                    Cow::Borrowed(unsafe { slices.next().unwrap_unchecked() })
114	                }
115	                _ => Cow::Owned(slices.fold(Vec::with_capacity(self.len()), |mut acc, it| {
116	                    acc.extend_from_slice(it);
117	                    acc
118	                })),
119	            }
120	        }
121	    }
122	}
