124	pub mod writer {
125	    use core::num::NonZeroUsize;
126	
127	    use crate::ZSlice;
128	
129	    #[derive(Debug, Clone, Copy)]
130	    pub struct DidntWrite;
131	
132	    pub trait Writer {
133	        fn write(&mut self, bytes: &[u8]) -> Result<NonZeroUsize, DidntWrite>;
134	        fn write_exact(&mut self, bytes: &[u8]) -> Result<(), DidntWrite>;
135	        fn remaining(&self) -> usize;
136	
137	        fn write_u8(&mut self, byte: u8) -> Result<(), DidntWrite> {
138	            self.write_exact(core::slice::from_ref(&byte))
139	        }
140	        #[inline(always)]
141	        fn write_zslice(&mut self, slice: &ZSlice) -> Result<(), DidntWrite> {
142	            self.write_exact(slice.as_slice())
143	        }
144	        fn can_write(&self) -> bool {
145	            self.remaining() != 0
146	        }
147	        /// Provides a buffer of exactly `len` uninitialized bytes to `write` to allow in-place writing.
148	        /// `write` must return the number of bytes it actually wrote.
149	        ///
150	        /// # Safety
151	        ///
152	        /// Caller must ensure that `write` return an integer lesser than or equal to the length of
153	        /// the slice passed in argument.
154	        unsafe fn with_slot<F>(&mut self, len: usize, write: F) -> Result<NonZeroUsize, DidntWrite>
155	        where
156	            F: FnOnce(&mut [u8]) -> usize;
157	    }
158	
159	    impl<W: Writer + ?Sized> Writer for &mut W {
160	        fn write(&mut self, bytes: &[u8]) -> Result<NonZeroUsize, DidntWrite> {
161	            (**self).write(bytes)
162	        }
163	        fn write_exact(&mut self, bytes: &[u8]) -> Result<(), DidntWrite> {
164	            (**self).write_exact(bytes)
165	        }
166	        fn remaining(&self) -> usize {
167	            (**self).remaining()
168	        }
169	        fn write_u8(&mut self, byte: u8) -> Result<(), DidntWrite> {
170	            (**self).write_u8(byte)
171	        }
172	        fn write_zslice(&mut self, slice: &ZSlice) -> Result<(), DidntWrite> {
173	            (**self).write_zslice(slice)
174	        }
175	        fn can_write(&self) -> bool {
176	            (**self).can_write()
177	        }
178	        /// # Safety
179	        ///
180	        /// Caller must ensure that `write` return an integer lesser than or equal to the length of
181	        /// the slice passed in argument.
182	        unsafe fn with_slot<F>(&mut self, len: usize, write: F) -> Result<NonZeroUsize, DidntWrite>
183	        where
184	            F: FnOnce(&mut [u8]) -> usize,
185	        {
186	            // SAFETY: same precondition as the trait method.
187	            unsafe { (**self).with_slot(len, write) }
188	        }
189	    }
190	
191	    pub trait BacktrackableWriter: Writer {
192	        type Mark;
193	
194	        fn mark(&mut self) -> Self::Mark;
195	        fn rewind(&mut self, mark: Self::Mark) -> bool;
196	    }
197	
198	    impl<W: BacktrackableWriter + ?Sized> BacktrackableWriter for &mut W {
199	        type Mark = W::Mark;
200	        fn mark(&mut self) -> Self::Mark {
201	            (**self).mark()
202	        }
203	        fn rewind(&mut self, mark: Self::Mark) -> bool {
204	            (**self).rewind(mark)
205	        }
206	    }
207	
208	    pub trait HasWriter {
209	        type Writer: Writer;
210	
211	        /// Returns the most appropriate writer for `self`
212	        fn writer(self) -> Self::Writer;
213	    }
214	}
