216	pub mod reader {
217	    use core::{fmt::Display, num::NonZeroUsize};
218	
219	    use crate::{ZBuf, ZSlice};
220	
221	    #[derive(Debug, Clone, Copy)]
222	    pub struct DidntRead;
223	
224	    impl Display for DidntRead {
225	        fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
226	            f.write_str("Didn't read")
227	        }
228	    }
229	
230	    #[cfg(feature = "std")]
231	    impl std::error::Error for DidntRead {}
232	
233	    pub trait Reader {
234	        fn read(&mut self, into: &mut [u8]) -> Result<NonZeroUsize, DidntRead>;
235	        fn read_exact(&mut self, into: &mut [u8]) -> Result<(), DidntRead>;
236	        fn remaining(&self) -> usize;
237	
238	        fn read_zbuf(&mut self, len: usize) -> Result<ZBuf, DidntRead> {
239	            let mut buf = ZBuf::empty();
240	            self.read_zslices(len, |s| buf.push_zslice(s))?;
241	            Ok(buf)
242	        }
243	
244	        /// Returns an iterator of `ZSlices` such that the sum of their length is _exactly_ `len`.
245	        fn read_zslices<F: FnMut(ZSlice)>(
246	            &mut self,
247	            len: usize,
248	            for_each_slice: F,
249	        ) -> Result<(), DidntRead>;
250	
251	        /// Reads exactly `len` bytes, returning them as a single `ZSlice`.
252	        fn read_zslice(&mut self, len: usize) -> Result<ZSlice, DidntRead>;
253	
254	        fn read_u8(&mut self) -> Result<u8, DidntRead> {
255	            let mut byte = 0;
256	            let read = self.read(core::slice::from_mut(&mut byte))?;
257	            if read.get() == 1 {
258	                Ok(byte)
259	            } else {
260	                Err(DidntRead)
261	            }
262	        }
263	
264	        fn can_read(&self) -> bool {
265	            self.remaining() != 0
266	        }
267	    }
268	
269	    impl<R: Reader + ?Sized> Reader for &mut R {
270	        #[inline(always)]
271	        fn read(&mut self, into: &mut [u8]) -> Result<NonZeroUsize, DidntRead> {
272	            (**self).read(into)
273	        }
274	        #[inline(always)]
275	        fn read_exact(&mut self, into: &mut [u8]) -> Result<(), DidntRead> {
276	            (**self).read_exact(into)
277	        }
278	        #[inline(always)]
279	        fn remaining(&self) -> usize {
280	            (**self).remaining()
281	        }
282	        #[inline(always)]
283	        fn read_zbuf(&mut self, len: usize) -> Result<ZBuf, DidntRead> {
284	            (**self).read_zbuf(len)
285	        }
286	        #[inline(always)]
287	        fn read_zslices<F: FnMut(ZSlice)>(
288	            &mut self,
289	            len: usize,
290	            for_each_slice: F,
291	        ) -> Result<(), DidntRead> {
292	            (**self).read_zslices(len, for_each_slice)
293	        }
294	        #[inline(always)]
295	        fn read_zslice(&mut self, len: usize) -> Result<ZSlice, DidntRead> {
296	            (**self).read_zslice(len)
297	        }
298	        #[inline(always)]
299	        fn read_u8(&mut self) -> Result<u8, DidntRead> {
300	            (**self).read_u8()
301	        }
302	        #[inline(always)]
303	        fn can_read(&self) -> bool {
304	            (**self).can_read()
305	        }
306	    }
307	
308	    pub trait BacktrackableReader: Reader {
309	        type Mark;
310	
311	        fn mark(&mut self) -> Self::Mark;
312	        fn rewind(&mut self, mark: Self::Mark) -> bool;
313	    }
314	
315	    impl<R: BacktrackableReader + ?Sized> BacktrackableReader for &mut R {
316	        type Mark = R::Mark;
317	        fn mark(&mut self) -> Self::Mark {
318	            (**self).mark()
319	        }
320	        fn rewind(&mut self, mark: Self::Mark) -> bool {
321	            (**self).rewind(mark)
322	        }
323	    }
324	
325	    pub trait AdvanceableReader: Reader {
326	        fn skip(&mut self, offset: usize) -> Result<(), DidntRead>;
327	        fn backtrack(&mut self, offset: usize) -> Result<(), DidntRead>;
328	        fn advance(&mut self, offset: isize) -> Result<(), DidntRead> {
329	            if offset > 0 {
330	                self.skip(offset as usize)
331	            } else {
332	                self.backtrack((-offset) as usize)
333	            }
334	        }
335	    }
336	
337	    #[derive(Debug, Clone, Copy)]
338	    pub struct DidntSiphon;
339	
340	    pub trait SiphonableReader: Reader {
341	        fn siphon<W>(&mut self, writer: &mut W) -> Result<NonZeroUsize, DidntSiphon>
342	        where
343	            W: crate::writer::Writer;
344	    }
345	
346	    pub trait HasReader {
347	        type Reader: Reader;
348	
349	        /// Returns the most appropriate reader for `self`
350	        fn reader(self) -> Self::Reader;
351	    }
352	}
