153	fn downsampling_validator(d: &Vec<DownsamplingItemConf>) -> bool {
154	    for item in d {
155	        if item
156	            .messages
157	            .iter()
158	            .any(|m| *m == DownsamplingMessage::Push)
159	        {
160	            tracing::warn!("In 'downsampling/messages' configuration: 'push' is deprecated and may not be supported in future versions, use 'put' and/or 'delete' instead");
161	        }
162	    }
163	    true
164	}
