208	#[derive(Debug, Clone, PartialEq, Eq)]
209	pub struct ConfRange {
210	    start: Option<u64>,
211	    end: Option<u64>,
212	}
213	
214	impl ConfRange {
215	    pub fn new(start: Option<u64>, end: Option<u64>) -> Self {
216	        Self { start, end }
217	    }
218	}
219	
220	impl RangeBounds<u64> for ConfRange {
221	    fn start_bound(&self) -> Bound<&u64> {
222	        match self.start {
223	            Some(ref start) => Bound::Included(start),
224	            None => Bound::Unbounded,
225	        }
226	    }
227	    fn end_bound(&self) -> Bound<&u64> {
228	        match self.end {
229	            Some(ref end) => Bound::Included(end),
230	            None => Bound::Unbounded,
231	        }
232	    }
233	}
234	
235	impl serde::Serialize for ConfRange {
236	    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
237	    where
238	        S: serde::Serializer,
239	    {
240	        serializer.serialize_str(&format!(
241	            "{}..{}",
242	            self.start.unwrap_or_default(),
243	            self.end.unwrap_or_default()
244	        ))
245	    }
246	}
247	
248	impl<'a> serde::Deserialize<'a> for ConfRange {
249	    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
250	    where
251	        D: serde::Deserializer<'a>,
252	    {
253	        struct V;
254	
255	        impl serde::de::Visitor<'_> for V {
256	            type Value = ConfRange;
257	
258	            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
259	                formatter.write_str("range string")
260	            }
261	
262	            fn visit_str<E>(self, v: &str) -> Result<Self::Value, E>
263	            where
264	                E: serde::de::Error,
265	            {
266	                let (start, end) = v
267	                    .split_once("..")
268	                    .ok_or_else(|| serde::de::Error::custom("invalid range"))?;
269	                let parse_bound = |bound: &str| {
270	                    (!bound.is_empty())
271	                        .then(|| bound.parse::<u64>())
272	                        .transpose()
273	                        .map_err(|_| serde::de::Error::custom("invalid range bound"))
274	                };
275	                Ok(ConfRange::new(parse_bound(start)?, parse_bound(end)?))
276	            }
277	        }
278	        deserializer.deserialize_str(V)
279	    }
280	}
