1297	    pub fn insert_json5(
1298	        &mut self,
1299	        key: &str,
1300	        value: &str,
1301	    ) -> Result<(), validated_struct::InsertionError> {
1302	        <Self as ValidatedMap>::insert_json5(self, key, value)
1303	    }
1304	
1305	    /// Tries to insert or update a JSON5 object in an array using a field filter
1306	    /// in the last key segment.
1307	    ///
1308	    /// A key of the form `<array-key>/<field-name>=<field-value>` addresses an
1309	    /// object inside the array stored at `<array-key>`. The `<field-name>` part
1310	    /// is not a config child key; it is a filter applied to objects contained in
1311	    /// the array. For example, `qos/network/id=rule1` loads the array at
1312	    /// `qos/network` and matches objects whose `id` field is the string `rule1`.
1313	    ///
1314	    /// When a field filter is present, `value` must be a single JSON5 object
1315	    /// containing the same string field value. The object replaces the first
1316	    /// matching array element, or is appended if none exists.
1317	    ///
1318	    /// Returns `true` if the field-filter operation was applied. If `key` does
1319	    /// not contain a field filter, this returns `false` and leaves the config
1320	    /// unchanged.
1321	    pub fn try_insert_json5_array_item(
1322	        &mut self,
1323	        key: &str,
1324	        value: &str,
1325	    ) -> Result<bool, validated_struct::InsertionError> {
1326	        let Some((prefix, field_value)) = key.split_once('=') else {
1327	            return Ok(false);
1328	        };
1329	        let (array_key, field_name) =
1330	            prefix
1331	                .rsplit_once('/')
1332	                .ok_or(validated_struct::InsertionError::Str(
1333	                    "missing field filter",
1334	                ))?;
1335	        let new_item = json5::from_str::<serde_json::Value>(value)?;
1336	        if new_item
1337	            .as_object()
1338	            .and_then(|map| map.get(field_name))
1339	            .and_then(|v| v.as_str())
1340	            != Some(field_value)
1341	        {
1342	            return Err(validated_struct::InsertionError::String(format!(
1343	                "field filter mismatch: value must be an object containing {field_name}=\"{field_value}\""
1344	            )));
1345	        }
1346	        let current = serde_json::from_str::<serde_json::Value>(
1347	            &self
1348	                .get_json(array_key)
