1420	            return Ok(false);
1421	        };
1422	        let (array_key, field_name) = prefix.rsplit_once('/').ok_or("missing field filter")?;
1423	        let current = serde_json::from_str::<serde_json::Value>(
1424	            &self.get_json(array_key).map_err(|err| zerror!("{err}"))?,
1425	        )?;
1426	        let serde_json::Value::Array(mut list) = current else {
1427	            bail!("not an array")
1428	        };
1429	        let prev_len = list.len();
1430	        list.retain(|item| match item {
1431	            serde_json::Value::Object(map) => {
1432	                map.get(field_name).and_then(|v| v.as_str()) != Some(field_value)
1433	            }
1434	            _ => true,
1435	        });
1436	        if list.len() != prev_len {
1437	            self.insert_json5(array_key, &serde_json::to_string(&list)?)?;
1438	        }
1439	        Ok(true)
1440	    }
