1885	                            Some(r) => r,
1886	                            None => return key_not_found(),
1887	                        },
1888	                        Err(_) => return key_not_found(),
1889	                    },
1890	                },
1891	                Value::Object(v) => v.entry(current).or_insert(Value::Null),
