1910	        let (plugin, key) = validated_struct::split_once(key, '/');
1911	        let new_value: Value = serde::Deserialize::deserialize(deserializer)?;
1912	        let value = self
1913	            .values
1914	            .as_object_mut()
1915	            .unwrap()
1916	            .entry(plugin)
1917	            .or_insert(Value::Null);
1918	        let new_value = value.clone().merge(key, new_value)?;
1919	        *value = if let Some(validator) = self.validator.upgrade() {
1920	            // New plugin configuration for compare with original configuration.
1921	            // Return error if it's not an object.
1922	            // Note: it's ok if original "new_value" is not an object: this can be some subkey of the plugin configuration. But the result of the merge should be an object.
1923	            // Error occurs  if the original plugin configuration is not an object itself (e.g. null).
1924	            let Some(new_plugin_config) = new_value.as_object() else {
1925	                return Err(format!(
1926	                    "Attempt to provide non-object value as configuration for plugin `{plugin}`"
1927	                )
1928	                .into());
1929	            };
1930	            // Original plugin configuration for compare with new configuration.
1931	            // If for some reason it's not defined or not an object, we default to an empty object.
1932	            // Usually this happens when no plugin with this name defined. Reject then should be performed by the validator with `plugin not found` error.
1933	            let empty_config = Map::new();
1934	            let current_plugin_config = value.as_object().unwrap_or(&empty_config);
1935	            match validator.check_config(plugin, key, current_plugin_config, new_plugin_config) {
1936	                // Validator made changes to the proposed configuration, take these changes
1937	                Ok(Some(val)) => Value::Object(val),
1938	                // Validator accepted the proposed configuration as is
1939	                Ok(None) => new_value,
1940	                // Validator rejected the proposed configuration
1941	                Err(e) => return Err(format!("{e}").into()),
1942	            }
1943	        } else {
1944	            new_value
1945	        };
1946	        Ok(())
1947	    }
1948	    fn get<'a>(&'a self, mut key: &str) -> Result<&'a dyn Any, GetError> {
1949	        let (current, new_key) = validated_struct::split_once(key, '/');
1950	        key = new_key;
1951	        let mut value = match self.values.get(current) {
1952	            Some(matched) => matched,
1953	            None => return Err(GetError::NoMatchingKey),
1954	        };
1955	        while !key.is_empty() {
1956	            let (current, new_key) = validated_struct::split_once(key, '/');
1957	            key = new_key;
1958	            let matched = match value {
1959	                serde_json::Value::Null
1960	                | serde_json::Value::Bool(_)
1961	                | serde_json::Value::Number(_)
1962	                | serde_json::Value::String(_) => return Err(GetError::NoMatchingKey),
1963	                serde_json::Value::Array(a) => a.get(match current.parse::<usize>() {
1964	                    Ok(i) => i,
1965	                    Err(_) => return Err(GetError::NoMatchingKey),
1966	                }),
1967	                serde_json::Value::Object(v) => v.get(current),
1968	            };
1969	            value = match matched {
1970	                Some(matched) => matched,
1971	                None => return Err(GetError::NoMatchingKey),
1972	            }
1973	        }
1974	        Ok(value)
1975	    }
1976	
1977	    type Keys = Vec<String>;
1978	    fn keys(&self) -> Self::Keys {
1979	        self.values.as_object().unwrap().keys().cloned().collect()
1980	    }
1981	
1982	    fn get_json(&self, mut key: &str) -> Result<String, GetError> {
1983	        let (current, new_key) = validated_struct::split_once(key, '/');
1984	        key = new_key;
1985	        let mut value = match self.values.get(current) {
1986	            Some(matched) => matched,
1987	            None => return Err(GetError::NoMatchingKey),
1988	        };
1989	        while !key.is_empty() {
1990	            let (current, new_key) = validated_struct::split_once(key, '/');
1991	            key = new_key;
1992	            let matched = match value {
1993	                serde_json::Value::Null
1994	                | serde_json::Value::Bool(_)
1995	                | serde_json::Value::Number(_)
1996	                | serde_json::Value::String(_) => return Err(GetError::NoMatchingKey),
1997	                serde_json::Value::Array(a) => a.get(match current.parse::<usize>() {
1998	                    Ok(i) => i,
1999	                    Err(_) => return Err(GetError::NoMatchingKey),
2000	                }),
2001	                serde_json::Value::Object(v) => v.get(current),
2002	            };
2003	            value = match matched {
2004	                Some(matched) => matched,
2005	                None => return Err(GetError::NoMatchingKey),
2006	            }
2007	        }
2008	        Ok(serde_json::to_string(value).unwrap())
