197	impl fmt::Debug for ZRuntimePool {
198	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
199	        let initialized = self
200	            .0
201	            .iter()
202	            .filter_map(|(runtime, cell)| cell.get().map(|_| runtime))
203	            .collect::<Vec<_>>();
204	        f.debug_struct("ZRuntimePool")
205	            .field("initialized", &initialized)
206	            .finish_non_exhaustive()
207	    }
