209	
210	impl ZRuntimePool {
211	    fn new() -> Self {
212	        Self(ZRuntime::iter().map(|zrt| (zrt, OnceLock::new())).collect())
213	    }
214	
215	    pub fn get(&self, zrt: &ZRuntime) -> &Handle {
216	        // Although the ZRuntime is called to use `zrt`, it may be handed over to another one
217	        // specified via the environmental variable.
218	        let param: &RuntimeParam = zrt.borrow();
219	        let zrt = match param.handover {
220	            Some(handover) => handover,
221	            None => *zrt,
222	        };
223	
224	        self.0
225	            .get(&zrt)
226	            .unwrap_or_else(|| panic!("The hashmap should contains {zrt} after initialization"))
227	            .get_or_init(|| {
228	                zrt.init()
229	                    .unwrap_or_else(|_| panic!("Failed to init {zrt}"))
230	            })
231	            .handle()
232	    }
233	}
234	
235	// If there are any blocking tasks spawned by ZRuntimes, the function will block until they return.
236	impl Drop for ZRuntimePool {
237	    fn drop(&mut self) {
238	        let handles: Vec<_> = self
239	            .0
240	            .drain()
241	            .filter_map(|(_name, mut rt)| {
242	                rt.take()
243	                    .map(|r| std::thread::spawn(move || r.shutdown_timeout(Duration::from_secs(1))))
244	            })
245	            .collect();
246	
247	        for hd in handles {
248	            let _ = hd.join();
249	        }
250	    }
251	}
