31	#[derive(Debug, Clone, Default, Eq)]
32	pub struct ZBuf {
33	    slices: SingleOrVec<ZSlice>,
34	}
35	
36	impl ZBuf {
37	    #[must_use]
38	    pub const fn empty() -> Self {
39	        Self {
40	            slices: SingleOrVec::empty(),
41	        }
42	    }
43	
44	    pub fn clear(&mut self) {
45	        self.slices.clear();
46	    }
47	
48	    #[inline(always)]
49	    pub fn zslices(&self) -> impl Iterator<Item = &ZSlice> + '_ {
50	        self.slices.as_ref().iter()
51	    }
52	
53	    pub fn zslices_mut(&mut self) -> impl Iterator<Item = &mut ZSlice> + '_ {
54	        self.slices.as_mut().iter_mut()
55	    }
56	
57	    pub fn into_zslices(self) -> impl Iterator<Item = ZSlice> {
58	        self.slices.into_iter()
59	    }
60	
61	    #[inline(always)]
62	    pub fn push_zslice(&mut self, zslice: ZSlice) {
63	        if !zslice.is_empty() {
64	            self.slices.push(zslice);
65	        }
66	    }
67	
68	    pub fn to_zslice(&self) -> ZSlice {
69	        let mut slices = self.zslices();
70	        match self.slices.len() {
71	            0 => ZSlice::empty(),
72	            // SAFETY: it's safe to use unwrap_unchecked() because we are explicitly checking the length is 1.
73	            1 => unsafe { slices.next().unwrap_unchecked().clone() },
74	            _ => slices
75	                .fold(Vec::new(), |mut acc, it| {
76	                    acc.extend(it.as_slice());
77	                    acc
78	                })
79	                .into(),
80	        }
